import React from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'



const MePageWrapper = styled.div `
width:90%;
margin:0 auto;
`


const MeBody = styled.div `
display:flex;
justify-content:center;
align-items:center;
`


const SeparationLineBig = styled.hr `
background-color:grey;
`

const LeftBodyPart = styled.div `
font-size:0.9rem;
width:30%;
display:flex;
justify-content:center;
align-items:flex-start;
flex-direction:column;
color:grey;
`

const RightBodyPart = styled.div `
width:70%;
`
const Hr = styled.div `
width:0;
height:1px;
background-color:#1C1C1C;
transition:all 0.3s ease-in;
`

const Messages = styled.div `
margin-top:20px;
&:hover {
	cursor:pointer;
}
&:hover ${Hr} {
	width:100%;
	color:#1C1C1C;
}
`

const MyItems = styled.div `
margin-top:20px;
&:hover {
	cursor:pointer;
}
&:hover ${Hr} {
	width:100%;

`

const MyProfile = styled.div `
margin-top:20px;
&:hover {
	cursor:pointer;
}
&:hover ${Hr} {
	width:100%;

`

const Settings = styled.div `
margin-top:20px;
&:hover {
	cursor:pointer;
}
&:hover ${Hr} {
	width:100%;

`

export default function Me () {
	return (
		<>
			<Header />
			<Navbar />
			<MePageWrapper>

				<SeparationLineBig/>
				<MeBody>
					<LeftBodyPart>
						<Messages>Messages<Hr /></Messages>
						<MyItems>My Items<Hr /></MyItems>
						<MyProfile>My Profile<Hr /></MyProfile>
						<Settings>Settings<Hr /></Settings>
					</LeftBodyPart>
					<RightBodyPart>

					</RightBodyPart>
				</MeBody>
			</MePageWrapper>
		</>
	)
}
